# ruff: noqa
from __future__ import annotations

from dataclasses import dataclass
from typing import Any

@dataclass(frozen=True, slots=True)
class CollectionSpec:
    name: str
    source: str
    element_expr: str
    filter_exprs: tuple[str, ...]

@dataclass(frozen=True, slots=True)
class CountOutputSpec:
    output_key: str
    mode: str
    source: str
    filter_exprs: tuple[str, ...] = ()

@dataclass(frozen=True, slots=True)
class SumSpec:
    output_key: str
    source: str
    term_expr: str
    filter_exprs: tuple[str, ...]

@dataclass(frozen=True, slots=True)
class LatestOutputSpec:
    output_key: str
    variable: str
    round_digits: int | None = None

